var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"20년 전, 가변 심도 강습 작전 <color=#ffd34c>트러블 슈팅</color>","JPN":"20年前、可変深度強襲作戦<color=#ffd34c>トラブルシューティング</color>","ENG":"20 years ago, Variable Depth Assault Operation <color=#ffd34c>Troubleshooting</color>","TWN":"20年前，可變深度強襲作戰<color=#ffd34c>故障排除</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"최종국면, <color=#ffd34c>시무르그 요격전</color>","JPN":"最終局面、<color=#ffd34c>シムルグ迎撃戦</color>","ENG":"Final Phase, <color=#ffd34c>Simurgh Interception</color>","TWN":"決戰時刻，<color=#ffd34c>西摩格攔截戰</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"웃기지 마……!! 그딴 게 최선이라고……!?","JPN":"ふざけるな……！！　それが最善だって……！？","ENG":"Don't make me laugh...! That's the best choice...?!","TWN":"開什麼玩笑……！！這就是最好的了……？！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 그냥 도망친 것뿐이잖아……!!","JPN":"それはただ逃げただけじゃないか……！！","ENG":"That's just running away...!!","TWN":"這不就是逃跑嗎……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나에게 있어서 최선이라는 건……!!","JPN":"アタシにとって最善ってのは……！！","ENG":"The best choice for me is...!","TWN":"對我來說最好的選擇是……！！"},"stage":{"bg":"SPACE_GRAVITY","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"고민하고, 결심하고, 상처입고, 극복하고, 다짐하고, 좌절하고, 다시 일어서고……!","JPN":"悩んで、決意して、傷ついて、乗り越えて、誓って、挫折して、また立ち上がって……！","ENG":"After thinking, deciding, getting hurt, overcoming, promising, being discouraged, and getting back up...!","TWN":"我思考過、決定過、受傷過、克服過、承諾過、沮喪過，也重新站起來過……！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"최후의 최후까지 할 수 있는 건 전부 다 해본 뒤에 내리는 마지막 선택이야!","JPN":"最後の最後まで、ギリギリまでやれることを全部やってから決めることだ！","ENG":"After doing everything that I could until the very end, this is the choice I made!","TWN":"這是我拼盡全力直到最後才做出的選擇！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 끝에 어떤 결말이 기다리고 있다고 해도……!!","JPN":"その先にどんな結末が待っていようとも……！！","ENG":"It doesn't matter what's waiting for me at the other end...!","TWN":"不管最後等待我的結局是什麼……！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"결코 후회가 남지 않도록!!","JPN":"決して後悔が残らないように！！","ENG":"I won't have any regrets!!","TWN":"我絕不再留下任何遺憾！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"부정. 연합 역시 멸망을 피하기 위해, 동원할 수 있는 모든 연산을 동원했습니다.","JPN":"否定。連合もまた滅亡を避けるために、できる限りの演算を算出しました。","ENG":"Negative. The Interstellar Alliance had also run every possible calculation to avoid devastation.","TWN":"否定。為了避免滅亡，聯盟也動用了一切可以動用的資源。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"아시모프께서는 유기체가 감당할 수 없는 긴 세월 동안, 그 문제만을 연산하셨습니다.","JPN":"アシモフは有機体が耐えられないほど長い期間、その問題の演算を繰り返しておられました。","ENG":"Asimov had calculated this problem for a time longer than an organism can handle.","TWN":"阿西莫夫在這個問題上花費了相當長的時間，比生物體能夠處理的時間還要長。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"재차 부정. 엄정하신 기계 장치의 신께서 내린 결론을 부정할 셈입니까?","JPN":"再度否定。厳正なる機械装置の神が下した結論を否定するつもりですか？","ENG":"Double negative. Are you denying the conclusion made by the impartial God of Machinery?","TWN":"再次否認。你要否認公正的機械之神得出的結論嗎？"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그딴 거 내 알 바 아니야!","JPN":"そんなの、アタシの知ったことじゃない。","ENG":"I don't care about that!","TWN":"那不關我的事！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"세계가 어쩌고, 멸망이 어쩌고, 신이 어쩌고 그딴 와닿지도 않는 이야기! 알 바 아니라고!","JPN":"世界がどうの、滅亡がどうの、神がどうの。そんな話、知ったことじゃないんだよ！","ENG":"All this mumbo-jumbo about the world ending and whatever gods! That's none of my business!","TWN":"世界也好，毀滅也好，還有你們的神也好，這些虛無縹緲的事情！和我有什麼關係！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 그저 내 앞에서 누군가가 죽지 않길 바랄 뿐이야!","JPN":"アタシはただアタシの目の前で誰かが死ぬところを見たくないだけだ！","ENG":"All I want is for no one to die on my watch!","TWN":"我只希望沒有人死在我面前！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"너희들이 시험이라는 이유로 죽이려고 했던, 내 소중한 전대원들을 구하고 싶을 뿐이라고!!","JPN":"おまえらが試験という名目で殺そうとした、アタシの大切な戦隊員たちを助けたいだけなんだ！！","ENG":"I just want to save my precious division members that you're trying to kill for your stupid test!","TWN":"我只是想拯救我那些你們以測試為名而試圖殺死的戰隊成員！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"엘부르즈 대검 파손. 물질 재구성까지 36초","JPN":"アルボルズ大剣破損。物質再構成まであと36秒。","ENG":"Alborz greatsword destroyed. Thirty-six seconds until material reconstruction.","TWN":"艾爾布勒茲損壞。距材料重構還需36秒。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL"},{"id":"L28_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"시무르그 이민선 본체, 대기권 돌입. 대기와의 마찰열로 인해 표면 온도 급상승.","JPN":"シムルグ移民船本体、大気圏突入。大気との摩擦熱により、表面温度急上昇。","ENG":"Simurgh Exodus Fleet, entering the atmosphere. Temperature rapidly rising due to friction heat.","TWN":"西摩格移民船本體進入大氣層。由於與大氣的摩擦，表面溫度迅速升高。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"경고. 이대로라면 당신도 무사하지 못할 겁니다.","JPN":"警告。このままだと、あなたも無事ではいられません。","ENG":"Warning. You will also not escape unharmed if this continues.","TWN":"警告。再繼續下去，你不可能活著離開這裡。"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"크윽!! 상관없어!!","JPN":"くうっ！！　構わない！！","ENG":"Khhkkk!! I don't care!!","TWN":"呃！！我才不管！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그 어떤 화염도 나를 막을 수는 없으니까!!","JPN":"どんな火炎であろうと、アタシを止めることはできない！！","ENG":"No flame can stop me!!","TWN":"任何火焰也阻擋不了我！！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"한 걸음만 1초만 더 빨랐으면 하는 후회는 이제 지긋지긋해!","JPN":"あと一歩、あと1秒でも早かったならと後悔するのは、もううんざりだ！","ENG":"I've had enough of regretting that I was one step sooner or one second earlier!","TWN":"我已經厭倦總是在來不及的悔恨當中！"},"stage":{"bg":"YAKSHA_02","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_10"},{"id":"L35_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"이번에야 말로……!","JPN":"今度こそ……！","ENG":"This time...!","TWN":"這一次……！"},"stage":{"bg":"TRAINING","bgm":"THEMA_CA_CAT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_11"},{"id":"L37_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"목숨이 다하는 한이 있더라도……! 여기서 널 쓰러트리고 모두를 구하겠어!","JPN":"命が尽きようと……！　ここでおまえを倒してみんなを助ける！","ENG":"Even if it costs me my life...! I'll defeat you and save everyone!","TWN":"即便賭上性命……我也要在這裡打倒你拯救大家！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_12"},{"id":"L38_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"사도 시무르그!","JPN":"使徒シムルグ！","ENG":"Apostle Simurgh!!","TWN":"使徒西摩格！"},"stage":{"bg":"YAKSHA_01","bgm":"THEMA_CA_CAT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_METAL_04","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CAT_IN_TRAILER_13"},{"id":"L46_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 이민선 시무르그, 메인 드라이브에 치명적인 손상.</color>","JPN":"<color=#ff3636>警告。移民船シムルグ、メインドライブに致命的な損傷。</color>","ENG":"<color=#ff3636>Warning. Exodus Fleet Simurgh... Critical damage to the main drive.</color>","TWN":"<color=#ff3636>警告！移民船西摩格，主驅動器嚴重損壞。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L47_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>경고. 이민선단 호위용 공간 도약 전투체. 시그널 로스트.</color>","JPN":"<color=#ff3636>警告。移民船団護衛用、空間跳躍戦闘体。シグナルロスト。</color>","ENG":"<color=#ff3636>Warning. Space-jumping Escort Fighter for Exodus Fleet... Signal Lost.</color>","TWN":"<color=#ff3636>警告！護衛人類移民船隊的空間跳躍戰鬥體，訊號丟失。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L48_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>이민선 시무르그, 지구 대기권에서 자유 낙하 중.</color>","JPN":"<color=#ff3636>移民船シムルグ、地球の大気圏より自由落下中。</color>","ENG":"<color=#ff3636>Exodus Fleet Simurgh... Currently in free fall through Earth's atmosphere.</color>","TWN":"<color=#ff3636>移民船西摩格，自由降落在地球大氣層中。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L2_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"시무르그, 항행 목표 변경─────────────","JPN":"シムルグ、航行目標変更─────────────","ENG":"Simurgh... Changing navigation target─────────────","TWN":"西摩格，航行目標變更─────────────"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L3_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>불가능.</color>","JPN":"<color=#ff3636>不可能。</color>","ENG":"<color=#ff3636>Impossible.</color>","TWN":"<color=#ff3636>無效。</color>"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L4_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"물질 재구성 프로토콜───────────────","JPN":"物質再構成プロトコル───────────────","ENG":"Initiating Material Reconstruction Protocol───────────────","TWN":"物質重組協議───────────────"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L5_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>불가능.</color>","JPN":"<color=#ff3636>不可能。</color>","ENG":"<color=#ff3636>Impossible.</color>","TWN":"<color=#ff3636>無效。</color>"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L6_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"인공지능 모듈 리부트. 재기동 절차 시행──────","JPN":"人工知能モジュールのリブート。再起動手続き遂行──────","ENG":"Rebooting Artificial Intelligence module. Reinitialize──────","TWN":"人工智慧模組重啟。執行重啟程式──────"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L7_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>불가능.</color>","JPN":"<color=#ff3636>不可能。</color>","ENG":"<color=#ff3636>Impossible.</color>","TWN":"<color=#ff3636>無效。</color>"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L8_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"냉철한 시무르그─────────────────","JPN":"冷徹なシムルグ─────────────────","ENG":"Cold-Hearted Simurgh─────────────────","TWN":"冷酷的西摩格─────────────────"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L9_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>AI 완전 침묵 확인.</color>","JPN":"<color=#ff3636>AI完全沈黙確認。</color>","ENG":"<color=#ff3636>Total AI silence confirmed.</color>","TWN":"<color=#ff3636>確認人工智慧完全沉默。</color>"},"stage":{"bg":"MAINSTREAM_7060010","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"인과 연산 결과값과 현실 사이의 변동 오차값 재측정 시도.","JPN":"因果演算の結果値と現実との変動誤差値の再測定開始。","ENG":"Attempting to remeasure the margin of error between calculated causality and reality.","TWN":"嘗試重新測量因果運算結果值與實際值之間的誤差。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L13_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"측정 완료.","JPN":"測定完了。","ENG":"Measurement complete.","TWN":"測量完成"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"현실 변동 오차율─────────────────","JPN":"現実変動誤差率─────────────────","ENG":"Reality margin of error─────────────────","TWN":"現實變動誤差率─────────────────"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L15_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>1.000000%</color>","JPN":"<color=#ff3636>1.000000%</color>","ENG":"<color=#ff3636>1.000000%</color>","TWN":"<color=#ff3636>1.000000%</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"현재, 용맹한 라마스 AI가 출격 대기 중.","JPN":"現在、勇猛なラマスAIが出撃待機中。","ENG":"Brave Lamas AI, currently ready to engage.","TWN":"目前，勇猛的拉瑪斯人工智慧正在待命出擊。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L17_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"지금 개입한다면, 1.000000%의 오차율을 보정. 연산한 결과에 다다를 수 있습니다.","JPN":"今介入すれば、1.000000%の誤差率を補正し、演算結果に至ることができます。","ENG":"Immediate intervention will allow for a 1.000000% error correction, bringing us to the computed result.","TWN":"如果現在介入，可以將誤差率校正為1.000000%，並得出計算結果。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L18_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"인과 수렴을 위한 인류 선별 프로세스를 속행하시겠습니까?","JPN":"因果収束のための人類選別プロセスを続行しますか？","ENG":"Proceed with the mankind selection process for causality convergence?","TWN":"是否繼續運行因果收斂的人類篩選程式？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"하이브리드 환상종이 결국 우주에 다다르는 것.","JPN":"ハイブリッド幻想種がついに宇宙に至ること。","ENG":"Hybrid Bygones eventually reaching outer space.","TWN":"混合幻想種最後到達宇宙。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"상처 입은 검은 짐승이 냉철한 시무르그와 대적하게 되는 것.","JPN":"傷ついた黒い獣が冷徹なシムルグと対敵すること。","ENG":"The wounded black beast standing against the Cold-Hearted Simurgh.","TWN":"受傷的黑獸將與冷酷的西摩格對決。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그 결과로 관리국 전대가 전력을 대거 상실한 채로 클리포트 게임에 돌입하게 되는 것.","JPN":"その結果、管理局の戦隊が戦力の大部分を喪失した状態でクリフォトゲームに突入すること。","ENG":"As a result, the Administration's divisions entering the Qliphoth Game with most of their strength lost.","TWN":"結果就是管理局戰隊在失去大量戰力的情況下進入了逆卡巴拉遊戲。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그리고 게임의 패배.","JPN":"そしてゲームでの敗北。","ENG":"And finally, defeat in the game.","TWN":"以及遊戲的失敗。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"모든 것은 이미 지나가버린 세계로부터 수차례 증명된 인과였을 터.","JPN":"幾多の世界が崩れ去る過程で、すでに証明された因果であるはず。","ENG":"Everything was merely a chain of causality, proven countless times in a world that has come and gone.","TWN":"一切或許早已被那個已經逝去的世界多次驗證為因果。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L29_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"저에게 있어, 당신은 여전히 이해할 수 없는 존재로군요.","JPN":"私にとって、あなたは依然として理解しがたい存在です。","ENG":"To me, you're still beyond my understanding.","TWN":"對我來說，你依然是個無法理解的存在。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"정해진 사건을 뒤틀지 않고, 또다시 세계로부터 <color=#ffd34c>변화</color>를 이끌어냈으니까요.","JPN":"決められた事件を捻じ曲げることなく、再び世界に<color=#ffd34c>変化</color>をもたらしたのですから。","ENG":"You once again brought about <color=#ffd34c>change</color> in this world, without disrupting the events already set in motion.","TWN":"沒有扭曲既定的事件，再次從世界中引出了<color=#ffd34c>變化</color>。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그러니 경의를 표합니다. 함장.","JPN":"ゆえに、敬意を払います、艦長。","ENG":"So I offer you my respect, Captain.","TWN":"所以我向你致敬，艦長。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"당신이 쌓아 올린 1.000000%의 <color=#ffd34c>충분한 원인</color>에 경의를.","JPN":"あなたが築き上げた、1.000000%の<color=#ffd34c>十分たる原因</color>に敬意を。","ENG":"To the 1.000000% of <color=#ffd34c>sufficient cause</color> you built, I offer my deepest respect.","TWN":"向你積累的1.000000%的<color=#ffd34c>充分原因</color>致敬。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"이 변화는 틀림없이 나비의 날개짓으로 작용하겠죠.","JPN":"この変化は必ず、蝶の羽ばたきとして作用することでしょう。","ENG":"This change will no doubt act as the flutter of a butterfly's wings.","TWN":"這變化必定會像蝴蝶的翅膀一樣起作用吧。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"성간 관리 연합 총괄 네비게이션 시스템, <color=#ffd34c>아시모프</color>가 명한다.","JPN":"星間管理連合の総括ナビゲーションシステム、<color=#ffd34c>アシモフ</color>が命じる。","ENG":"Interstellar Administration Alliance Central Navigation System, <color=#ffd34c>Asimov</color>, issues this command.","TWN":"星際管理聯合總管導航系統，是由我<color=#ffd34c>阿西莫夫</color>控制。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"이 순간, 세계 인과율 변동을 포착.","JPN":"この瞬間、世界の因果律変動を捕捉。","ENG":"At this moment, a change in the world's causality has been detected.","TWN":"這一刻，將會捕捉到世界因果率的變化。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"현 시간부로 연합의 모든 함대는 인과 수렴을 위한 인류 선별 프로세스를 중단.","JPN":"現時刻をもって、連合の全ての艦隊は因果収束のための人類選別プロセスを中断。","ENG":"Effective immediately, all ships of the Alliance will cease the mankind selection process for causality convergence.","TWN":"從現在起，聯合艦隊將停止所有為因果收斂而運行的人類篩選程式。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"세피로트 나무 탐사 플랜을 재개하기 위해.","JPN":"セフィロト探査プランを再開するため。","ENG":"To resume the Tree of Sephiroth Expedition Plan.","TWN":"這是為了重新啟動生命樹的探險計畫。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"이 세계, <color=#ffd34c>달의 뒷면</color>에 정박하고 월면 기지를 구축.","JPN":"この世界、<color=#ffd34c>月の裏側</color>に停泊し、月面基地を構築。","ENG":"We will anchor on the <color=#ffd34c>dark side of the moon</color> and construct a lunar base.","TWN":"在<color=#ffd34c>月球背面</color>停泊並建立月面基地。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"<color=#ffd34c>세피라 포인트</color>를 탐색한다.","JPN":"<color=#ffd34c>セフィラポイント</color>を探索する。","ENG":"And begin the search for the <color=#ffd34c>Sephira Point</color>.","TWN":"探索<color=#ffd34c>生命樹質點</color>。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"subtitle","speaker":null,"text":{"KOREA":"몇 개월 뒤","JPN":"数か月後","ENG":"A few months later","TWN":"幾個月後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"subtitle","speaker":null,"text":{"KOREA":"오퍼레이션 <color=#ffd34c>클리포트 게임</color> 최종국면","JPN":"オペレーション<color=#ffd34c>クリフォトゲーム</color>最終局面","ENG":"Operation <color=#ffd34c>Qliphoth Game</color> Final Phase","TWN":"作戰<color=#ffd34c>逆卡巴拉遊戲</color>決戰時刻"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>7시 방향 2km 지역, 제 4종 침식파 발생.</color>","JPN":"<color=#ffd34c>7時方向2km地点、第4種侵食波発生。</color>","ENG":"<color=#ffd34c>Category 4 Corruption ray detected 2km to your 7 o'clock.</color>","TWN":"<color=#ffd34c>7點鐘方向2km區域，出現4級侵蝕波。</color>"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L47_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>대형 변이종 접근.</color>","JPN":"<color=#ffd34c>大型変異種接近。</color>","ENG":"<color=#ffd34c>Large mutated species approaching.</color>","TWN":"<color=#ffd34c>大型變異體正在接近。</color>"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아르콘 전대, 카멜롯 전대. 소멸.</color>","JPN":"<color=#ffd34c>アルコン戦隊、キャメロット戦隊。消滅。</color>","ENG":"<color=#ffd34c>ARKON Division. CAMELOT Division. Annihilated.</color>","TWN":"<color=#ffd34c>阿勒坤小隊，卡梅羅小隊，全滅。</color>"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>긴급 구원 요청이 접수되었습니다.</color>","JPN":"<color=#ffd34c>緊急救援要請を受け付けました。</color>","ENG":"<color=#ffd34c>Emergency MEDEVAC request received.</color>","TWN":"<color=#ffd34c>緊急救援請求已被接受。</color>"},"stage":{"bg":"MAINSTREAM_002000","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"대, 대장님! 당장 후퇴해야 합니다! 이대론 전멸이에요!","JPN":"た、隊長！　ただちに後退すべきです！　このままでは全滅です！","ENG":"S-sir! We have to fall back! They'll wipe us out at this rate!","TWN":"長、長官！我們得馬上撤退！這樣下去會全滅的！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"바보 같은 소리 하지 마!","JPN":"バカげたことを言うな！","ENG":"Don't give me that crap!","TWN":"別講這種蠢話！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"우리가 여기서 물러나면, 세상은 끝장이다!","JPN":"ここで我々が退けば、世界は終わるのだぞ！","ENG":"If we retreat right now, it'll be the end of the world!","TWN":"我們現在要是撤退的話，這個世界就完蛋了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"하, 하지만 벌써 A급 카운터들도 거의 전멸했다고요!","JPN":"で、ですが、すでにA級カウンターも全滅しかけています！","ENG":"But nearly all the Grade A Counters are already down!","TWN":"但、但是，連A級制裁者們都幾乎全滅了啊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"우리가 뭘 어떻게 할 방법이 없어요!","JPN":"我々にはどうすることもできません！","ENG":"There's nothing else we can do!","TWN":"我們又能怎麼辦，根本沒辦法啊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"걱정 마라. 조금만 버텨.","JPN":"案ずるな。あと少しだけ持ち堪えろ。","ENG":"Don't worry. Hang on just a little longer.","TWN":"別擔心，再堅持一下。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"조금만 더 버티면...... 펜릴 전대가 온다.","JPN":"あと少し持ち堪えれば……フェンリル戦隊が来る。","ENG":"If we stand our ground just a little longer... The Fenrir Division will be here.","TWN":"再多堅持一會兒的話……芬里爾戰隊就要來了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"그때까지만...... 그때까지만 버티면 돼!","JPN":"それまで……それまで持ち堪えればいい！","ENG":"So hang on... Just hold out until then!","TWN":"只要堅持到那時候……只要堅持到那時候就可以了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"저건......","JPN":"あれは……","ENG":"That's...","TWN":"那是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"글레입니르다!","JPN":"グレイプニルだ！","ENG":"That's Gleipnir!","TWN":"格萊伊尼勒！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SHILED_ADMIN_NULL_COMMANDER","text":{"KOREA":"강습함 글레입니르! 살아 있었어!","JPN":"強襲艦グレイプニル！　生存していたんだ！","ENG":"Assault Ship Gleipnir! They're still alive!","TWN":"強襲戰艦·格萊伊尼勒！他們還活著！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"정말로...... 살아 돌아왔다고......?","JPN":"本当に……生きて帰ってきたのか……？","ENG":"They... Really made it back?","TWN":"真的……活著回來了……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOLDIER_ADMIN_NULL_NULL","text":{"KOREA":"펜릴 전대가 왔다! 대장님이 왔다고!","JPN":"フェンリル戦隊が来た！　隊長が来たぞ！","ENG":"The Fenrir Division is here! The Commander is here!","TWN":"芬里爾戰隊來了！隊長來了！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"대장님, 명령을!","JPN":"隊長、ご命令を！","ENG":"Your orders, Commander!","TWN":"隊長，請下達指令！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHILED_ADMIN_NULL_COMMANDER","face":"UNIT_IDLE"},"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SOLDIER_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"생존한 모든 부대는 글레입니르를 중심으로 재편성!","JPN":"すべての残存部隊を、グレイプニルを中心に再編成！","ENG":"All remaining units are to regroup around Gleipnir!","TWN":"所有存活部隊，以格萊伊尼勒為中心重新進行編隊！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"전방의 제 4종 침식체는 우리 펜릴 전대가 맡는다.","JPN":"前方の第4種侵食体は、我々フェンリル戦隊が引き受ける。","ENG":"Fenrir Division will handle the Category 4 Corrupted Objects.","TWN":"前方的4類侵蝕體就交給我們芬里爾戰隊。"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"단숨에 격파한다. 가자!","JPN":"一気に撃破する。行くぞ！","ENG":"Take them down swiftly. Let's go!","TWN":"一口氣擊破它們，上！"},"stage":{"bg":"PROLOGUE_03","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"우주, <color=#ffd34c>달의 뒷면</color> 월면 기지","JPN":"宇宙、<color=#ffd34c>月の裏側</color>の月面基地。","ENG":"Outer space, <color=#ffd34c>Dark side of the moon</color>, Lunar base","TWN":"宇宙，<color=#ffd34c>月球背面</color>月面基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"세피라 포인트.\\n그것은 머나먼 과거, 달의 뒷면에 존재했던 차원 균열의 좌표.","JPN":"セフィラポイント。\\nそれは遥か昔、月の裏側に存在していた次元の亀裂の座標。","ENG":"Sephira Point.\\nIt's the coordinates of a dimensional rift that once existed on the dark side of the moon, long ago.","TWN":"生命樹質點。\\n那是遙遠的過去，是存在於月球背面的次元裂縫座標。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"연합이 오랫동안 찾아왔던 세피로트 나무가 존재하는 차원과 이어진 유일한 통로.","JPN":"連合が長年探してきたセフィロトが存在する次元とつながる唯一の通路。","ENG":"The only passage connected to the dimension where the Tree of Sephiroth, long-sought by the Alliance, resides.","TWN":"是聯盟尋找已久的與生命樹相連的唯一通道。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"연합의 레거시 데이터에 따르면, 인류가 최초로 이곳에 접촉한 것은 1969년의 아폴로 계획.","JPN":"連合のレガシーデータによると、人類が初めてこの場所に降り立ったのは1969年のアポロ計画の時。","ENG":"According to the Alliance's legacy data, humanity first made contact with this site during the Apollo Program in 1969.","TWN":"根據聯盟戰紀資料，人類首次接觸此地是在1969年的阿波羅計畫。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"달을 조사하던 저궤도 탐사선의 선원들이 정체불명의 소리를 듣게 된 것이 그 시작이었다.","JPN":"月を調査していた低軌道探査船の船員たちの耳に、正体不明の音声が届いたことがその始まりだった。","ENG":"It all began when the crew of a low-orbit lunar probe heard an unidentified sound.","TWN":"調查月球的低軌道探測船的船員們聽到了不明聲音，這就是事情的開端。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"대기가 존재하지 않는 달의 뒷면에서 들려오는, 들릴 리 없는 기이한 노랫소리.","JPN":"大気が存在しない月の裏側から聞こえてくる、聞こえるはずのない奇妙な歌声。","ENG":"A strange song, echoing from the dark side of the moon, where no atmosphere exists... and no sound should be heard.","TWN":"這是來自月球背面的、不可能存在的怪異歌聲。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"당시 인류는 그 신호를 전파 충돌에 의한 해프닝 정도로 치부하였지만…….","JPN":"当時、人類はその信号を電波の衝突によるハプニング程度にしか捉えなかったが……","ENG":"At the time, humanity dismissed the signal as nothing more than a radio interference anomaly...","TWN":"當時人類以為是電波訊號碰撞偶然引發了那個訊號……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"그로부터 수백년 뒤.","JPN":"それから数百年後。","ENG":"Centuries later...","TWN":"那之後的數百年。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"성간이동이 가능해진 인류는 달과 관련된 몇 가지 사실을 밝혀낸다.","JPN":"星間移動が可能になった人類は、月に関わるいくつかの新事実を突き止める。","ENG":"With interstellar travel now within humanity's reach, several truths about the moon have come to light.","TWN":"能夠進行星際移動的人類揭示了一些與月球相關的事實。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"첫째. 달 탐사를 통해 입수한 월석에서 강력한 에너지 파장의 흔적이 검출되었다는 것.","JPN":"その1。月の探査を通じて入手した月の石から、強力なエネルギーの痕跡が検出されたこと。","ENG":"First, traces of a powerful energy wavelength were detected in lunar rock samples collected during exploration.","TWN":"第一，透過月球探測獲得的月石中檢測到了強烈的能量波動。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"둘째. 해당 에너지 파장의 발생 시점이 물질계 발생 시점과 거의 일치한다는 것.","JPN":"その2。そのエネルギーの発生時点が物質界の発生時点とほぼ一致すること。","ENG":"Second, the origin point of this energy wavelength closely matches the birth of the material realm.","TWN":"第二，該能量波長的發生時間點幾乎與物質界的發生時間點一致。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"셋째. 해당 에너지 파장을 분석한 결과, 카운터의 CRF 파장과 유사한 패턴을 가졌다는 것.","JPN":"その3。そのエネルギーの波長を分析した結果、カウンターのCRF波長と類似したパターンを持っていたこと。","ENG":"Third, analysis of the energy wavelength revealed that the pattern closely resembles that of the CRF wavelength of Counters.","TWN":"第三，分析該能量波長的結果表明，其具有與制裁者的CRF波長相似的模式。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"이 세가지 사실에 근거하여, 연합은 한 가지 가설을 세운다.","JPN":"この3つの事実に基づき、連合はひとつの仮説を立てる。","ENG":"Based on these three findings, the Alliance formed a single hypothesis.","TWN":"基於這三個事實，聯盟提出了一個假設。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"외장 아베스타 드라이브 삽입. 탐사 유닛 준비 완료.","JPN":"外装アヴェスター・ドライブ挿入。探査ユニット準備完了。","ENG":"Injecting external Avesta Drive. Expedition unit ready.","TWN":"外置阿貝斯塔引擎插入。探測單元準備完畢。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L6_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신성 반응</color> 관측을 위해, 탐사 유닛, <color=#ffd34c>망원경</color>을 사출.","JPN":"<color=#ffd34c>神聖反応</color>の観測のため、探査ユニット<color=#ffd34c>望遠鏡</color>を射出。","ENG":"Deploying expedition unit <color=#ffd34c>Telescope</color> to observe signs of <color=#ffd34c>the Divinity response</color>.","TWN":"<color=#ffd34c>神聖反應</color>觀測，為了探測單位，發射<color=#ffd34c>望遠鏡</color>。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_FIRE"},{"id":"L7_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"탐사를 속행합니다.","JPN":"探査を続行します。","ENG":"Resuming the expedition.","TWN":"快速進行探索。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"그것은 <color=#ffd34c>세피로트 나무</color> 가설.","JPN":"それは<color=#ffd34c>セフィロト</color>の仮説である。","ENG":"It's the <color=#ffd34c>Tree of Sephiroth</color> hypothesis.","TWN":"那是<color=#ffd34c>生命樹</color>假說。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"이 세계는 마치 나무의 가지처럼, 수없이 많은 평행 세계로 분화되어 있으며.","JPN":"この世界はまるで木の枝のように、数多のパラレルワールドに分かれており。","ENG":"A hypothesis that this world, like the branches of a great tree, has splintered into countless parallel dimensions.","TWN":"這個世界就像樹枝一樣，分化成無數個平行世界。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"무수히 분화된 다차원의 평행 세계가 결국 하나의 뿌리로부터 출발했으리라는 가설.","JPN":"無数に分かれた多次元のパラレルワールドは結局、ひとつの根から始まっているという仮説。","ENG":"And that all these divergent, multi-dimensional worlds can be traced back to a single root.","TWN":"無數分化的多次元平行世界最後都源自一個根源的假設。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"그 뿌리는 태초에 물질계를 현현시킨 <color=#ffd34c>신성</color>의 작용이자.","JPN":"その根は、原初の時に物質界を顕現させた<color=#ffd34c>神聖</color>の作用であり、","ENG":"That root is the <color=#ffd34c>Divinity</color> that first gave form to the material world.","TWN":"其根源是最初顯現在物質界的<color=#ffd34c>神聖</color>作用。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"현실개변력의 총체라고 할 수 있는 모든 가능성의 <color=#ffd34c>근원</color>.","JPN":"現実改変力の総体とも言うべき、あらゆる可能性の<color=#ffd34c>根源</color>。","ENG":"It's the <color=#ffd34c>origin</color> of all possibilities, and the foundation of what we call the Counter Reality Force.","TWN":"可以說是現實變革力的總和，一切可能性的<color=#ffd34c>根源</color>。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"연합은 그것을 세계를 만드는 법칙.\\n<color=#ffd34c>세피로트 나무</color>라고 불렀다.","JPN":"連合はそれを世界を作る法則、\\n<color=#ffd34c>セフィロト</color>と呼んだ。","ENG":"The Alliance named it the law of creating a world.\\nIn other words, the <color=#ffd34c>Tree of Sephiroth</color>.","TWN":"聯盟稱其為創造世界的法則。\\n<color=#ffd34c>名為生命樹</color>。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"세피로트 나무 가설에 근거.\\n연합은 그것에 다다르기 위해 수단과 방법을 가리지 않았다.","JPN":"セフィロトの仮説に基づき、\\n連合はそれに至るためにあらゆる手段を講じた。","ENG":"Based on the Tree of Sephiroth Hypothesis,\\nthe Alliance stopped at nothing to reach it.","TWN":"基於生命樹假說。\\n聯盟為了達到那個目標，不擇手段。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"인류의 구제를 위해.","JPN":"人類の救済のために。","ENG":"To save humanity.","TWN":"為了拯救人類。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"침식으로부터 안전한 곳을 찾기 위해.","JPN":"侵食の脅威から逃れられる、安全な場所を探すために。","ENG":"To find a haven untouched by Corruption.","TWN":"為了尋找一個免受侵蝕的安全地方。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"이제는 들려올 리 없는, 달의 노래가 들려오는 곳으로 향하기 위해.","JPN":"もはや聞こえるはずもない、月の歌が聞こえる場所をめざして。","ENG":"To reach the place where the moon's song can be still heard, though it should be impossible.","TWN":"為了前往那不再受月之歌聲侵擾的地方。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"이미 모성조차 상실해 버린 연합은 오랜 시간, 수많은 세계를 떠돌며 달의 뒷면을 탐사했다.","JPN":"すでに母星すら失った連合は、長年にわたって数多の世界を巡り月の裏側を探査した。","ENG":"With their homeworld already gone, the Alliance scoured the dark side of the moon, endlessly drifting from world to world through the ages.","TWN":"已經失去母性的聯盟，長時間在無數世界中漂泊，探索著月球的背面。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"narration","speaker":null,"text":{"KOREA":"그러나 세피로트 나무의 존재는 어디까지나 가설의 영역.","JPN":"しかしセフィロトの存在はあくまで仮説の領域。","ENG":"However, the Tree of Sephiroth remained within the realm of hypothesis.","TWN":"不過生命樹的存在只是一個假設。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"이미 오래전에 소멸해버린 차원 균열에 다다르는 것은\\n유한한 생명을 가진 이들에게는 불가능에 가까운 일.","JPN":"とうの昔に消滅している次元の亀裂に至ることは\\n限りある命を持つ者にとっては不可能に近い。","ENG":"Reaching a dimensional rift that vanished long ago is an almost impossible task for those bound by mortal lifespans.","TWN":"對於生命有限的人來說，抵達早已消失的次元裂縫幾乎是不可能的事。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"결국, 유기체의 필연적 한계를 극복할 수 없는 연합은 인간의 사명을 기계에게 부여한다.","JPN":"結局、有機体の必然的な限界を克服できなかった連合は、人間の使命を機械に負わせた。","ENG":"In the end, unable to overcome the inherent limits of organic life, the Alliance entrusts humanity's mission to machines.","TWN":"最後，由於無法突破有機體的局限，聯盟將人類的使命賦予了機械。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"언젠가 자신들이 만든 피조물이 낙원을 연산해낼 날을 기도하면서.","JPN":"いつか自分たちが作り出した被造物が、楽園の位置をはじき出すことを願って。","ENG":"Praying for the day when their own creation would one day compute paradise into being.","TWN":"祈禱著有一天他們創造的物體能夠演算出樂園出現的那一天。"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"VOID","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"망원경에 의한 관측 지점 벡터 변환. 우주 잔류 침식파에 대한 간섭 중화.","JPN":"望遠鏡による観測地点のベクター変換。宇宙残留侵食波に対する干渉中和。","ENG":"Adjusting observation vector via telescope. Neutralizing interference from Corruption rays remaining in space.","TWN":"透過望遠鏡的觀測點向量轉換。和宇宙殘留侵蝕波的干擾中和。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L33_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"우주 잔류 침식파 중화 작업 완료.","JPN":"宇宙残留侵食波の中和作業完了。","ENG":"Neutralization of Corruption rays remaining in space complete.","TWN":"宇宙殘留侵蝕波中和作業完成。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L34_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"신성 반응 관측을 시작합니다.","JPN":"神聖反応の観測を始めます。","ENG":"Initiating observation of the Divinity response.","TWN":"開始觀測神聖反應。"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L35_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-17 ─────────────────","JPN":"セクター17 ─────────────────","ENG":"Sector-17 ─────────────────","TWN":"第17區 ─────────────────"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L36_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L37_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-51 ─────────────────","JPN":"セクター51 ─────────────────","ENG":"Sector-51 ─────────────────","TWN":"第51區 ─────────────────"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L38_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L39_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-85, 섹터-28, 섹터-62 ─────────","JPN":"セクター85、セクター28、セクター62 ─────────","ENG":"Sector-85, Sector-28, Sector-62 ─────────","TWN":"第85區，第28區，第62區 ─────────"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L40_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"COUNTERSIDE_SPACE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L46_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"……함장.","JPN":"……艦長。","ENG":"...Captain.","TWN":"……艦長。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L47_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"당신도 알다시피, 이 세계의 모든 것은 인과율에 의해 철저히 조율되고 있습니다.","JPN":"あなたもご存知のように、この世界の全ては因果律により徹底的に調整されています。","ENG":"As you already know, every aspect of this world is finely tuned by the laws of causality.","TWN":"你也知道，這個世界上的一切都被因果律嚴格地調節著。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"이에 따라, 모든 세계는 확실하게 멸망점을 향해 수렴하게 되어 있죠.","JPN":"これにより、全ての世界は確実に滅亡に向かって収束するようになっています。","ENG":"As a result, every world is destined to converge upon its own point of destruction.","TWN":"因此，所有世界都會無可避免地走向滅亡。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"성간 연합을 포함. 제가 관측했던 그 어떤 세계도 멸망을 피할 수는 없었습니다.","JPN":"星間連合を含め、私が観測したどの世界も滅亡を回避することはできませんでした。","ENG":"Even the Interstellar Alliance was no exception. Of all the worlds I've observed, not one escaped destruction.","TWN":"包括星際聯盟在內，我所觀察到的任何世界都無法避免滅亡。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그것은 틀림없이 <color=#ffd34c>신</color>이 결정한 세계의 법칙.","JPN":"それは紛うことなく、<color=#ffd34c>神</color>が定められし世界の法則。","ENG":"It is, without a doubt, the law of the world as ordained by <color=#ffd34c>God</color>.","TWN":"這無疑是<color=#ffd34c>神</color>決定的世界法則。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"따라서 <color=#ffd34c>탐미엘</color>이 세피로트 나무의 신성을 장악하고 있는 이상.","JPN":"従って、<color=#ffd34c>タミエル</color>がセフィロトの神聖を掌握している限り、","ENG":"As long as <color=#ffd34c>Tammiel</color> holds dominion over the Divinity of the Tree of Sephiroth,","TWN":"因此<color=#ffd34c>塔米爾</color>掌控著生命樹的神性。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"멸망이 확정되어 버린 세계에서 세피라 포인트를 발견하는 것은 불가능하겠죠.","JPN":"滅亡が確定した世界でセフィラポイントを見つけることは叶わないでしょう。","ENG":"discovering the Sephira Point in a world doomed to collapse is simply impossible.","TWN":"在已經註定滅亡的世界中，發現生命樹質點是不可能的吧。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-11, 섹터-39, 섹터-72 ─────────","JPN":"セクター11、セクター39、セクター72 ─────────","ENG":"Sector-11, Sector-39, Sector-72 ─────────","TWN":"第11區，第39區，第72區 ─────────"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L6_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L7_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-02, 섹터-66, 섹터-93 ─────────","JPN":"セクター02、セクター66、セクター93 ─────────","ENG":"Sector-02, Sector-66, Sector-93 ─────────","TWN":"第02區，第66區，第93區 ─────────"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L8_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L11_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"하지만 이 세계는 예정된 인과로부터 1.000000%만큼의 오차율이 발생한 세계.","JPN":"しかしこの世界は予定された因果から、1.000000%の誤差率が発生した世界。","ENG":"However, this world exhibits a 1.000000% deviation from its preordained causality.","TWN":"但是這個世界是從預定的因果中產生了1.000000%誤差率的世界。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"미약한 가능성이지만, 어쩌면 이 세계는 다른 결과를 맞이할지도 모릅니다.","JPN":"ごく小さな可能性ですが、もしかするとこの世界は違う結果を迎えるかもしれません。","ENG":"The odds are slim, but perhaps this world is capable of reaching a different outcome.","TWN":"雖然可能性微弱，但這個世界或許會迎來不同的結局。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그러니 궁금하군요, 함장.","JPN":"興味深いです、艦長。","ENG":"That makes me wonder, Captain.","TWN":"所以很好奇，艦長。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"인과율에 벗어난 결과를 마주하게 되는 순간, 과연 당신이 어떤 선택을 내리게 될지.","JPN":"因果律から逸れた結果を目の当たりにした時、あなたはどのような選択をするのか。","ENG":"When you're faced with a result beyond the bounds of causality... I wonder what choice you'll make.","TWN":"當你面對超越因果律的結果時，不知道你會做出怎樣的選擇。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"그 선택이 또 한 번 제 연산을 뛰어넘을 수 있을지.","JPN":"そしてその選択が、再度私の演算を越えうるのか。","ENG":"And whether that choice will surpass my calculations once more.","TWN":"那個選擇是否還能再次超越我的計算。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-07, 섹터-19, 섹터-91 ─────────","JPN":"セクター07、セクター19、セクター91 ─────────","ENG":"Sector-07, Sector-19, Sector-91 ─────────","TWN":"第07區，第19區，第91區 ─────────"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L19_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>클리어.</color>","JPN":"<color=#ffd34c>クリア。</color>","ENG":"<color=#ffd34c>Clear.</color>","TWN":"<color=#ffd34c>清除。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L20_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"섹터-20, 섹터-36, 섹터-32 ─────────","JPN":"セクター20、セクター36、セクター32 ─────────","ENG":"Sector-20, Sector-36, Sector-32 ─────────","TWN":"第20區，第36區，第32區 ─────────"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L21_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신성 반응 확인.</color>","JPN":"<color=#ffd34c>神聖反応を確認。</color>","ENG":"<color=#ffd34c>Divinity response detected.</color>","TWN":"<color=#ffd34c>確認神聖反應。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP5"},{"id":"L22_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>섹터-32</color>로부터 부분적 신성 반응 관측되었습니다.","JPN":"<color=#ffd34c>セクター32</color>より部分的神聖反応が観測されました。","ENG":"Partial Divinity response has been observed from <color=#ffd34c>Sector-32</color>.","TWN":"<color=#ffd34c>觀測到來自第32區的部分神聖反應</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L25_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"섹터-32로부터 관측된 신성 반응의 패턴을 분석.","JPN":"セクター32から観測された神聖反応のパターンを分析。","ENG":"Analyzing the pattern of a Divinity response has been observed in Sector-32.","TWN":"分析從第32區觀測到的神聖反應模式。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"패턴을 역산하여, 세피로트 나무가 존재하는 세피라 포인트의 좌표를…… ","JPN":"パターンを逆算し、セフィロトが存在するセフィラポイントの座標を……","ENG":"By reverse-calculating the pattern, the coordinates of the Sephira Point tied to the Tree of Sephiroth could be within reach...","TWN":"反向推演模式，確定存在生命樹的生命樹質點的座標……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"음?","JPN":"……これは……？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"MAINSTREAM_000003","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>긴급상황 발생. 각 클리파로부터 차원 계면 융해 현상 관측. </color>","JPN":"<color=#ffd34c>緊急事態発生。各クリファ次元より次元界面融解現象を観測。</color>","ENG":"<color=#ffd34c>Emergency alert. Dimension surface dissolution detected in each Qlipha.</color>","TWN":"<color=#ffd34c>發生緊急狀況。從各逆卡巴拉觀測到次元邊界熔解現象。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L32_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>융해된 차원 계면으로부터 거대 이상침식파 접근 중.</color>","JPN":"<color=#ffd34c>融解した次元界面より巨大異常侵食波が接近中。</color>","ENG":"<color=#ffd34c>Large abnormal Corruption ray approaching from the dissolved dimension surface.</color>","TWN":"<color=#ffd34c>正在接近被溶解的次元介面中的巨大異常侵蝕波。</color>"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L35_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"세계 침식률. 급속 상승 중.","JPN":"世界侵食率、急速に上昇中。","ENG":"Global Corruption rate... increasing at an exponential rate.","TWN":"世界侵蝕率急速上升中。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"세피라 포인트의 관측을 시도한 것만으로 침식률이 빠르게 치솟는군.","JPN":"セフィラポイントの観測を試みただけで、これほどまで急激に侵食率が上昇するとは。","ENG":"Even attempting to observe the Sephira Point causes the Corruption rate to spike rapidly.","TWN":"僅僅嘗試觀測生命樹質點，侵蝕率就迅速飆升了。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"누군가 세계의 진실에 다다르게 만들 바에는, 차라리 세계 그 자체를 무너트려 버리겠다는 사고 방식.","JPN":"誰かに世界の真実に至ることを許すくらいなら、いっそ世界そのものを破壊するという思考。","ENG":"A mindset that would rather destroy the world itself than allow anyone to uncover its truth.","TWN":"思維方式是與其讓某人接近世界的真相，不如將世界本身摧毀。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"과연, 탐미엘다운 발상이지만…….","JPN":"タミエルらしい発想と言えるが……","ENG":"That's exactly the kind of thinking expected from Tammiel...","TWN":"真不愧是塔米爾的想法……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>레거시 데이터베이스 검색 중.</color>","JPN":"<color=#ffd34c>レガシーデータベースを検索中。</color>","ENG":"<color=#ffd34c>Searching the legacy database.</color>","TWN":"<color=#ffd34c>正在搜索舊版資料庫。</color>"},"stage":{"bg":"TERRA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L42_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에너지 시그니처 매치 확인.</color>","JPN":"<color=#ffd34c>エネルギーシグネチャーマッチ確認。</color>","ENG":"<color=#ffd34c>Energy signature match confirmed.</color>","TWN":"<color=#ffd34c>確認能量訊號匹配。</color>"},"stage":{"bg":"TERRA","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"TYPING_LOOP"},{"id":"L45_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"사도 라마스, 이민선으로부터 호위용 공간 도약 전투체를 사출.","JPN":"使徒ラマス、移民船より護衛用空間跳躍戦闘体を射出。","ENG":"Apostle Lamas, deploy the Space-jumping Escort Fighter from the Exodus Fleet.","TWN":"護衛型空間跳躍戰鬥體從移民船發射，使徒拉瑪斯。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"연합의 모든 함대는 제1종 전투배치. 전방의 목표를 섬멸한다.","JPN":"連合の全艦隊は第1種戦闘配置へ。前方のターゲットを殲滅せよ。","ENG":"All Alliance ships, assume Category 1 battle formation. Annihilate all targets ahead.","TWN":"聯盟所有艦隊進入一級戰鬥部署。殲滅前方目標。"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"섬멸 대상…….","JPN":"殲滅対象……","ENG":"Annihilation target...","TWN":"殲滅目標……"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별 코드.</color>","JPN":"<color=#ffd34c>識別コード。</color>","ENG":"<color=#ffd34c>Identification code.</color>","TWN":"<color=#ffd34c>識別代碼。</color>"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"<color=#ff3636>세피라의 수호자.</color>","JPN":"<color=#ff3636>セフィラの守護者。</color>","ENG":"<color=#ff3636>Guardian of Sephira.</color>","TWN":"<color=#ff3636>生命樹守護者。</color>"},"stage":{"bg":"MAINSTREAM_000003","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"}]`);export{e as default};